module comparator(
	input [3:0] a,
	input [3:0] b,
	output equal,
	output greater,
	output less);
  wire _n01 = a[0] ^ b[0];
  wire _n02 = a[1] ^ b[1];
  wire _n03 = a[2] ^ b[2];
  wire _n04 = a[3] ^ b[3];
  assign equal = ~_n01 & ~_n02 & ~_n03 & ~_n04;
assign greater = (a > b);
assign less = (a < b);

endmodule
